import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; @singleton class SettingsCacheDatasource { final SharedPreferences _prefs; SettingsCacheDatasource(this._prefs); Future<void> set(String key, String value) => _prefs.setString(key, value); String? get(String key) => _prefs.getString(key); Future<void> remove(String key) => _prefs.remove(key); Future<void> clear() => _prefs.clear(); }
